import type { DatamodelEnum, Field, Model } from '@prisma/dmmf'

import { PRISMA_TO_TS_TYPE } from './scalar-map'

function scalarToTs(prismaType: string): string {
  return PRISMA_TO_TS_TYPE[prismaType] ?? 'unknown'
}

function fieldToTsType(field: Field): string {
  let base: string
  if (field.kind === 'scalar') {
    base = scalarToTs(field.type)
  } else if (field.kind === 'unsupported') {
    base = 'unknown'
  } else {
    // enum or object reference: use the type name directly
    base = field.type
  }
  return field.isList ? `${base}[]` : base
}

/** Builds the read model interface, including all fields (scalar, enum, and relation). */
export function buildModelInterface(model: Model): string {
  const lines: string[] = []
  if (model.documentation) {
    lines.push(`/** ${model.documentation} */`)
  }
  lines.push(`export interface ${model.name} {`)
  for (const field of model.fields) {
    if (field.documentation) {
      lines.push(`  /** ${field.documentation} */`)
    }
    const optional = !field.isRequired || field.hasDefaultValue ? '?' : ''
    lines.push(`  ${field.name}${optional}: ${fieldToTsType(field)}`)
  }
  lines.push('}')
  return lines.join('\n')
}

/**
 * Builds the input type for create operations.
 * Relation fields are excluded; auto-generated fields (IDs with defaults, `@updatedAt`, etc.) are optional.
 */
export function buildCreateInput(model: Model): string {
  const lines: string[] = [`export interface ${model.name}CreateInput {`]
  for (const field of model.fields) {
    if (field.kind === 'object') continue
    const base = field.kind === 'scalar' ? scalarToTs(field.type) : field.type
    const tsType = field.isList ? `${base}[]` : base
    const isAutoProvided = field.hasDefaultValue || field.isId || field.isUpdatedAt || !field.isRequired
    lines.push(`  ${field.name}${isAutoProvided ? '?' : ''}: ${tsType}`)
  }
  lines.push('}')
  return lines.join('\n')
}

/**
 * Builds the input type for update operations.
 * All writable scalar/enum fields are optional; ID and read-only fields are excluded.
 */
export function buildUpdateInput(model: Model): string {
  const lines: string[] = [`export interface ${model.name}UpdateInput {`]
  for (const field of model.fields) {
    if (field.kind === 'object' || field.isId || field.isReadOnly) continue
    const base = field.kind === 'scalar' ? scalarToTs(field.type) : field.type
    const tsType = field.isList ? `${base}[]` : base
    lines.push(`  ${field.name}?: ${tsType}`)
  }
  lines.push('}')
  return lines.join('\n')
}

/** Builds the filter type used in `findMany`'s `where` clause (all scalar/enum fields, all optional). */
export function buildWhereInput(model: Model): string {
  const lines: string[] = [`export interface ${model.name}WhereInput {`]
  for (const field of model.fields) {
    if (field.kind === 'object' || field.kind === 'unsupported') continue
    const base = field.kind === 'scalar' ? scalarToTs(field.type) : field.type
    const tsType = field.isList ? `${base}[]` : base
    lines.push(`  ${field.name}?: ${tsType}`)
  }
  lines.push('}')
  return lines.join('\n')
}

/** Builds the unique lookup type used in `findUnique`, `update`, and `delete` operations. */
