import type { Generator, GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'

import { generateRestClient } from './generate-rest-client'

function resolveEnvValue(envValue: { fromEnvVar: string | null; value: string | null }): string {
  if (envValue.fromEnvVar) {
    const resolved = process.env[envValue.fromEnvVar]
    if (resolved === undefined) {
      throw new Error(`Environment variable ${envValue.fromEnvVar} referenced in generator output is not set`)
    }
    return resolved
  }
  if (envValue.value === null) {
    throw new Error('Generator output path is not configured')
  }
  return envValue.value
}

/** Prisma generator that produces a typed REST API client from the datamodel. */
export class RestApiClientGenerator implements Generator {
  readonly name = 'prisma-rest-api-client'

  async getManifest(_config: GeneratorConfig): Promise<GeneratorManifest> {
    return {
      prettyName: 'Prisma REST API Client',
      defaultOutput: 'generated/rest-client',
      requiresEngines: [],
    }
  }

  async generate(options: GeneratorOptions): Promise<void> {
    const outputDir = resolveEnvValue(options.generator.output!)
    await generateRestClient({ dmmf: options.dmmf, outputDir })
  }
}

