import { buildModelCrudClient, buildRootClient } from '../crud-builder'

const minimalModel = {
  name: 'Post',
  dbName: null,
  schema: null,
  primaryKey: null,
  uniqueFields: [],
  uniqueIndexes: [],
  fields: [],
} as const

describe('buildModelCrudClient', () => {
  it('uses native private field for baseUrl', () => {
    const result = buildModelCrudClient(minimalModel as any)
    expect(result).toContain('#baseUrl')
  })

  it('generates all five CRUD methods', () => {
    const result = buildModelCrudClient(minimalModel as any)
    expect(result).toContain('async findMany(')
    expect(result).toContain('async findUnique(')
    expect(result).toContain('async create(')
    expect(result).toContain('async update(')
    expect(result).toContain('async delete(')
  })

  it('uses the lower-cased model name as the URL resource path', () => {
    const result = buildModelCrudClient(minimalModel as any)
    expect(result).toContain('/post')
  })

  it('returns null from findUnique on 404', () => {
    const result = buildModelCrudClient(minimalModel as any)
    expect(result).toContain('if (res.status === 404) return null')
  })

  it('uses PATCH for update', () => {
    const result = buildModelCrudClient(minimalModel as any)
    expect(result).toContain("method: 'PATCH'")
  })

  it('uses DELETE for delete', () => {
    const result = buildModelCrudClient(minimalModel as any)
    expect(result).toContain("method: 'DELETE'")
  })

  it('serialises where params as URL search params', () => {
    const result = buildModelCrudClient(minimalModel as any)
    expect(result).toContain('url.searchParams.set')
  })
})

