  it('declares a typed property for each model', () => {
    const result = buildRootClient(['User', 'Post'])
    expect(result).toContain('readonly user: UserRestClient')
    expect(result).toContain('readonly post: PostRestClient')
  })

  it('instantiates each model client in the constructor', () => {
    const result = buildRootClient(['User', 'Post'])
    expect(result).toContain('this.user = new UserRestClient(baseUrl)')
    expect(result).toContain('this.post = new PostRestClient(baseUrl)')
  })

  it('exports a RestApiClient class', () => {
    const result = buildRootClient(['User'])
    expect(result).toContain('export class RestApiClient')
  })
})

